/**
 * Handle user created — send welcome notification on all configured channels.
 */
private async handleUserCreated(event: UserCreatedEvent): Promise<void> {
  this.logger.info(`Sending welcome notification for user ${event.user.id}`);

  const subject = 'Welcome to TaskFlow Pro!';
  const body = `Hi ${event.user.name}, welcome to TaskFlow Pro! Your account has been created.`;
  const userId = event.user.id;

  // Email
  await this.sendNotification(
    {
      recipient: event.user.email,
      subject,
      body,
      channel: 'email',
      type: 'user:welcome',
    },
    userId,
  );

  // SMS — only if user has a phone number
  if (event.user.phone) {
    await this.sendNotification(
      {
        recipient: event.user.phone,
        subject,
        body,
        channel: 'sms',
        type: 'user:welcome',
      },
      userId,
    );
  }

  // Webhook
  await this.sendNotification(
    {
      recipient: event.user.email,
      subject,
      body,
      channel: 'webhook',
      type: 'user:welcome',
    },
    userId,
  );
}

/**
 * Handle user updated — send profile update notification on all configured channels.
 */
private async handleUserUpdated(event: UserUpdatedEvent): Promise<void> {
  this.logger.info(`Sending profile update notification for user ${event.user.id}`);

  const subject = 'Profile Updated';
  const body = `Hi ${event.user.name}, your profile has been updated. Changed: ${event.changes.join(', ')}.`;
  const userId = event.user.id;

  // Email
  await this.sendNotification(
    {
      recipient: event.user.email,
      subject,
      body,
      channel: 'email',
      type: 'user:profile-updated',
    },
    userId,
  );

  // SMS — only if user has a phone number
  if (event.user.phone) {
    await this.sendNotification(
      {
        recipient: event.user.phone,
        subject,
        body,
        channel: 'sms',
        type: 'user:profile-updated',
      },
      userId,
    );
  }

  // Webhook
  await this.sendNotification(
    {
      recipient: event.user.email,
      subject,
      body,
      channel: 'webhook',
      type: 'user:profile-updated',
    },
    userId,
  );
}

